mapper.select:

select o.*, u.real_name as user_name, i.instrument_name
from biz_reservation_order o
left join sys_user u on u.id = o.user_id
left join biz_instrument i on i.id = o.instrument_id
where o.deleted = 0

  and o.order_type = #{orderType}


  and o.order_status = #{status}


  and (o.order_no like concat('%', #{keyword}, '%')
  or u.real_name like concat('%', #{keyword}, '%')
  or i.instrument_name like concat('%', #{keyword}, '%'))


  and o.submit_time >= #{submitStart}


  and o.submit_time <= #{submitEnd}


  and o.department_id = #{filterDepartmentId}


  and exists (
  select 1 from biz_reservation_audit ar
  left join sys_user au on au.id = ar.auditor_id
  where ar.order_id = o.id and au.real_name like concat('%', #{auditorKeyword}, '%')
  )


  and coalesce(o.final_amount, o.estimated_amount, 0) >= #{minAmount}


  and coalesce(o.final_amount, o.estimated_amount, 0) <= #{maxAmount}


  and o.owner_user_id = #{operatorId}


  and o.department_id = #{scopeDepartmentId}

order by o.create_time desc
limit #{offset}, #{pageSize}


select count(1)
from biz_reservation_order o
where o.deleted = 0

  and o.order_type = #{orderType}


  and o.order_status = #{status}


  and (o.order_no like concat('%', #{keyword}, '%')
  or exists(select 1 from sys_user u where u.id = o.user_id and u.real_name like concat('%', #{keyword}, '%'))
  or exists(select 1 from biz_instrument i where i.id = o.instrument_id and i.instrument_name like concat('%', #{keyword}, '%')))


  and o.submit_time >= #{submitStart}


  and o.submit_time <= #{submitEnd}


  and o.department_id = #{filterDepartmentId}


  and exists (
  select 1 from biz_reservation_audit ar
  left join sys_user au on au.id = ar.auditor_id
  where ar.order_id = o.id and au.real_name like concat('%', #{auditorKeyword}, '%')
  )


  and coalesce(o.final_amount, o.estimated_amount, 0) >= #{minAmount}


  and coalesce(o.final_amount, o.estimated_amount, 0) <= #{maxAmount}


  and o.owner_user_id = #{operatorId}


  and o.department_id = #{scopeDepartmentId}

select o.*, u.real_name as user_name, i.instrument_name
from biz_reservation_order o
left join sys_user u on u.id = o.user_id
left join biz_instrument i on i.id = o.instrument_id
where o.user_id = #{userId}
  and o.deleted = 0

  and o.order_type = #{orderType}

order by o.create_time desc
limit #{offset}, #{pageSize}

select count(1)
from biz_reservation_order o
where o.user_id = #{userId}
  and o.deleted = 0

  and o.order_type = #{orderType}


select count(1) from biz_reservation_order
where instrument_id = #{instrumentId} and order_type = 'MACHINE' and deleted = 0
and order_status in ('PENDING_AUDIT', 'WAITING_USE', 'IN_USE')
and reserve_start < #{reserveEnd} and reserve_end > #{reserveStart}
and id <> #{excludeOrderId}

mapper.update:
update biz_reservation_order
set order_status=#{orderStatus}, audit_status=#{auditStatus}, pay_status=#{payStatus}, settlement_status=#{settlementStatus}, final_amount=#{finalAmount}, approve_time=#{approveTime}, finish_time=#{finishTime}, cancel_reason=#{cancelReason}, remark=#{remark}, update_time=#{updateTime}
where id=#{id}

update biz_reservation_order
set order_status='SETTLING', update_time=#{updateTime}
where id=#{id} and deleted=0 and order_status='WAITING_SETTLEMENT' and (pay_status is null or pay_status <> 'PAID')

mapper.select:
select count(1)
from biz_reservation_order o
where o.deleted = 0

  and o.create_time >= #{startTime}


  and o.create_time <= #{endTime}


  and o.department_id = #{scopeDepartmentId}

select count(1)
from biz_reservation_order o
where o.deleted = 0
  and o.order_status = 'COMPLETED'
  and coalesce(o.settlement_status, '') not in ('CONFIRMED', 'REFUNDED')

  and o.create_time >= #{startTime}


  and o.create_time <= #{endTime}


  and o.department_id = #{scopeDepartmentId}

select count(1)
from biz_reservation_order o
where o.deleted = 0
  and o.order_status = 'WAITING_SETTLEMENT'

  and o.create_time >= #{startTime}


  and o.create_time <= #{endTime}


  and o.department_id = #{scopeDepartmentId}

select count(1)
from biz_reservation_order o
where o.deleted = 0
  and o.settlement_status = 'CONFIRMED'
  and coalesce(o.pay_status, '') <> 'PAID'

  and o.create_time >= #{startTime}


  and o.create_time <= #{endTime}


  and o.department_id = #{scopeDepartmentId}

select coalesce(avg(timestampdiff(minute, o.create_time, now()) / 60.0), 0)
from biz_reservation_order o
where o.deleted = 0
  and o.order_status = 'WAITING_SETTLEMENT'

  and o.create_time >= #{startTime}


  and o.create_time <= #{endTime}


  and o.department_id = #{scopeDepartmentId}

mapper.sql:
select 'COMPLETED_UNSETTLED' as anomaly_type, '已完成未结算' as anomaly_label, o.id as order_id, o.order_no as order_no, s.id as settlement_id, s.settlement_no as settlement_no, o.user_id as user_id, u.real_name as user_name, '订单已完成但结算未确认' as detail, o.create_time as create_time from biz_reservation_order o left join biz_settlement_record s on s.order_id = o.id left join sys_user u on u.id = o.user_id where o.deleted = 0 and o.order_status = 'COMPLETED' and (s.id is null or s.settle_status = 'PENDING')
and o.create_time >= #{startTime}
and o.create_time <= #{endTime}
and o.department_id = #{scopeDepartmentId}
union all select 'WAITING_SETTLEMENT' as anomaly_type, '待结算滞留' as anomaly_label, o.id as order_id, o.order_no as order_no, s.id as settlement_id, s.settlement_no as settlement_no, o.user_id as user_id, u.real_name as user_name, '订单长时间处于待结算状态' as detail, o.create_time as create_time from biz_reservation_order o left join biz_settlement_record s on s.order_id = o.id left join sys_user u on u.id = o.user_id where o.deleted = 0 and o.order_status = 'WAITING_SETTLEMENT'
and o.create_time >= #{startTime}
and o.create_time <= #{endTime}
and o.department_id = #{scopeDepartmentId}
union all select 'CONFIRMED_UNPAID' as anomaly_type, '已结算未支付' as anomaly_label, o.id as order_id, o.order_no as order_no, s.id as settlement_id, s.settlement_no as settlement_no, o.user_id as user_id, u.real_name as user_name, '结算已确认但订单支付状态不是已支付' as detail, o.create_time as create_time from biz_reservation_order o inner join biz_settlement_record s on s.order_id = o.id and s.settle_status = 'CONFIRMED' left join sys_user u on u.id = o.user_id where o.deleted = 0 and coalesce(o.pay_status, '') <> 'PAID'
and o.create_time >= #{startTime}
and o.create_time <= #{endTime}
and o.department_id = #{scopeDepartmentId}
union all select 'REFUNDED_UNMATCHED' as anomaly_type, '已退款未冲正' as anomaly_label, o.id as order_id, o.order_no as order_no, s.id as settlement_id, s.settlement_no as settlement_no, o.user_id as user_id, u.real_name as user_name, '订单支付已退款，但结算记录未标记为已退款' as detail, o.create_time as create_time from biz_reservation_order o left join biz_settlement_record s on s.order_id = o.id left join sys_user u on u.id = o.user_id where o.deleted = 0 and o.pay_status = 'REFUNDED' and (s.id is null or s.settle_status <> 'REFUNDED')
and o.create_time >= #{startTime}
and o.create_time <= #{endTime}
and o.department_id = #{scopeDepartmentId}

